def can_make_square(grid):
    # Check all four possible 2x2 squares in a 3x3 grid
    for i in range(2):
        for j in range(2):
            # Count 'B' and 'W' in the 2x2 square
            b_count = 0
            w_count = 0
            for x in range(i, i + 2):
                for y in range(j, j + 2):
                    if grid[x][y] == 'B':
                        b_count += 1
                    else:
                        w_count += 1
            # If already all same or only one different, return True
            if b_count >= 3 or w_count >= 3:
                return True
    return False
